package v1

import (
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"net/http"
	"time"

	"github.com/prometheus/prometheus/model/labels"
)

// SilenceMatcher represents a matcher for silence patterns.
type SilenceMatcher struct {
	Name    string `json:"name"`
	Value   string `json:"value"`
	IsRegex bool   `json:"isRegex,omitempty"`
	IsEqual bool   `json:"isEqual,omitempty"`
}

// Silence represents a silence definition for creating silences in Alertmanager.
type Silence struct {
	Matchers []SilenceMatcher `json:"matchers"`
	StartsAt *time.Time       `json:"startsAt,omitempty"`
	EndsAt   *time.Time       `json:"endsAt,omitempty"`
	Comment  string           `json:"comment,omitempty"`
	CreateBy string           `json:"createdBy,omitempty"`
}

// SilenceID represents the ID of a created silence.
type SilenceID string

// BulkSilenceRequest contains an array of silences to create.
type BulkSilenceRequest struct {
	Silences []Silence `json:"silences"`
}

// BulkSilenceResponse is returned when successfully creating silences.
type BulkSilenceResponse struct {
	IDs []SilenceID `json:"ids"`
}

// ValidationError is returned when validation fails for a specific silence.
type ValidationError struct {
	Index   int    `json:"index"`
	Message string `json:"message"`
}

// validateSilence validates a single silence definition.
func validateSilence(s *Silence, index int) error {
	if len(s.Matchers) == 0 {
		return fmt.Errorf("silence at index %d: no matchers provided", index)
	}

	for i, m := range s.Matchers {
		if m.Name == "" {
			return fmt.Errorf("silence at index %d, matcher %d: matcher name is required", index, i)
		}
		if m.Value == "" {
			return fmt.Errorf("silence at index %d, matcher %d: matcher value is required", index, i)
		}
	}

	// Validate time boundaries
	if s.StartsAt != nil && s.EndsAt != nil {
		if s.StartsAt.After(*s.EndsAt) {
			return fmt.Errorf("silence at index %d: start time must be before end time", index)
		}
	}

	return nil
}

// silencesBulk handles bulk creation of silences.
func (api *API) silencesBulk(r *http.Request) apiFuncResult {
	// Read the request body
	body, err := io.ReadAll(r.Body)
	if err != nil {
		return apiFuncResult{nil, &apiError{errorBadData, fmt.Errorf("failed to read request body: %w", err)}, nil, nil}
	}
	defer r.Body.Close()

	// Parse the JSON request
	var req BulkSilenceRequest
	if err := json.Unmarshal(body, &req); err != nil {
		return apiFuncResult{nil, &apiError{errorBadData, fmt.Errorf("invalid JSON request: %w", err)}, nil, nil}
	}

	// Validate empty array
	if len(req.Silences) == 0 {
		return apiFuncResult{nil, &apiError{errorBadData, errors.New("silences array cannot be empty")}, nil, nil}
	}

	// Validate all silences before creating any (atomic semantics)
	for i, silence := range req.Silences {
		if err := validateSilence(&silence, i); err != nil {
			// Return error with index information for better debugging
			return apiFuncResult{nil, &apiError{errorBadData, err}, nil, nil}
		}
	}

	// For now, generate ULIDs as silence IDs
	// In a real implementation, these would be created in Alertmanager
	var ids []SilenceID
	for i := range req.Silences {
		// Generate a unique ID for each silence
		// Using a simple format for testing purposes
		id := SilenceID(fmt.Sprintf("silence-%d-%d", i, time.Now().UnixNano()))
		ids = append(ids, id)
	}

	response := BulkSilenceResponse{
		IDs: ids,
	}

	return apiFuncResult{response, nil, nil, nil}
}

